#include <stdio.h>

int main(void) {
    int valor;
    int suma = 0;

    printf("Ingrese valores positivos. Use 0 para terminar:\n");
    scanf("%d", &valor);

    while (valor != 0) {
        if (valor > 0) {
            suma = suma + valor;
        }
        scanf("%d", &valor);
    }

    printf("Suma de positivos: %d\n", suma);
    return 0;
}

